                completionHandler(.useCredential, credential)
            } else {
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
        }
    }
    
    private func validateCertificatePinning(serverTrust: SecTrust, domain: String) -> Bool {
        guard domain.hasSuffix("example.com") else {
            return false
        }
        
        let policy = SecPolicyCreateSSL(true, domain as CFString)
        SecTrustSetPolicies(serverTrust, policy)
        
        var secresult = SecTrustResultType.invalid
        let status = SecTrustEvaluate(serverTrust, &secresult)
        
        guard status == errSecSuccess,
              secresult == .unspecified || secresult == .proceed else {
            return false
        }
        
        guard let serverCertificate = SecTrustGetCertificateAtIndex(serverTrust, 0) else {
            return false
        }
        
        let serverCertificateData = SecCertificateCopyData(serverCertificate) as Data
        let serverCertificateHash = sha256(data: serverCertificateData)
        
        if productionPinnedHashes.contains(serverCertificateHash) {
            return true
        }
        
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        for i in 0..<certificateCount {
            guard let certificate = SecTrustGetCertificateAtIndex(serverTrust, i) else {
                continue
            }
            
            let certificateData = SecCertificateCopyData(certificate) as Data
            let publicKey = extractPublicKey(from: certificate)
            
            if let publicKey = publicKey {
                let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, nil) as Data?
                if let publicKeyData = publicKeyData {
                    let publicKeyHash = sha256(data: publicKeyData)
                    if productionPinnedHashes.contains(publicKeyHash) {
                        return true
                    }
                }
            }
        }
        
        return false
    }
    
    private func extractPublicKey(from certificate: SecCertificate) -> SecKey? {
        let policy = SecPolicyCreateBasicX509()
        var trust: SecTrust?
        let status = SecTrustCreateWithCertificates(certificate, policy, &trust)
        
        guard status == errSecSuccess, let trust = trust else {
            return nil
        }
        
        return SecTrustCopyPublicKey(trust)
    }
    
    private func sha256(data: Data) -> String {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        let hashData = Data(hash)
        return "sha256/" + hashData.base64EncodedString()
    }
